import subprocess
from pathlib import Path
seqs={}; name=None
for line in Path('/app/sequences.fasta').read_text().splitlines():
    if line.startswith('>'): name=line[1:].strip(); seqs[name]=''
    else: seqs[name]+=line.strip().lower()
comp=str.maketrans('acgt','tgca')
rc=lambda s:s.translate(comp)[::-1]
def tm(seq):
    return float(subprocess.check_output(['oligotm','-tp','1','-sc','1','-mv','50','-dv','2','-n','0.8','-d','500',seq], text=True).strip())
inp=seqs['input']
fc=[]; rcands=[]
for L in range(15,46):
    f=inp[691:691+L]; r=rc(inp[209-L:209]); tf=tm(f); tr=tm(r)
    if 58<=tf<=72: fc.append((L,tf,f))
    if 58<=tr<=72: rcands.append((L,tr,r))
print('input candidates',len(fc),len(rcands))
best=None
for a in fc:
    for b in rcands:
        d=abs(a[1]-b[1]); score=(d, abs(a[0]-22)+abs(b[0]-22))
